// ================================================================
// CODE NODE — Prepare Tracking Data
// Workflow: Clinera | Tracking Meta CAPI + GA4
//
// Recibe payload de Clinera (con o sin wrapper "body") y prepara:
// 1. Payload Meta CAPI (con PII hasheado SHA-256)
// 2. Payload GA4 Measurement Protocol (con client_id deterministico)
// ================================================================

// ============= VARIABLES EDITABLES =============
const EVENT_NAME_META = "Lead";          // Lead | Schedule | Purchase | CompleteRegistration
const EVENT_NAME_GA4  = "generate_lead"; // snake_case GA4 recommended event
const EVENT_VALUE     = 0;
const EVENT_CURRENCY  = "CLP";
// ===============================================

const crypto = require('crypto');

// Helper: SHA-256 hash con trim + lowercase (requerido por Meta CAPI)
const sha256 = (val) => {
  if (!val) return '';
  return crypto.createHash('sha256').update(val.toString().trim().toLowerCase()).digest('hex');
};

// Aceptar payload con wrapper "body" o flat
const raw = $input.first().json;
const b = raw.body || raw;

// ----- Datos del contacto -----
const contacto = b.contacto || b.contact || {};
const contactoId = (contacto.id || b.contacto_id || b.id || Date.now().toString()).toString();
const email = (contacto.email || b.email || '').toString().trim().toLowerCase();
const phoneRaw = (contacto.telefono || contacto.phone || b.telefono || b.phone || '').toString();
const phoneDigits = phoneRaw.replace(/[^0-9]/g, '');
const firstName = (contacto.nombre || contacto.first_name || b.nombre || b.first_name || '').toString().trim();
const lastName  = (contacto.apellido || contacto.last_name || b.apellido || b.last_name || '').toString().trim();

// ----- Browser tracking (opcional, si Clinera lo envia) -----
const fbp = b.fbp || contacto.fbp || '';
const fbc = b.fbc || contacto.fbc || '';
const userAgent = b.client_user_agent || (raw.headers && raw.headers['user-agent']) || '';
const ipAddress = b.client_ip_address ||
  (raw.headers && raw.headers['x-forwarded-for'] && raw.headers['x-forwarded-for'].split(',')[0].trim()) ||
  (raw.headers && raw.headers['x-real-ip']) || '';

// ----- Atribucion -----
const fbclid = b.fbclid || contacto.fbclid || '';
const gclid  = b.gclid  || contacto.gclid  || '';
const sourceUrl = b.event_source_url || b.url || 'https://clinera.io';

// ----- Event ID unico para deduplicacion browser + server -----
const eventId = b.event_id || ('clinera_' + contactoId + '_' + Date.now());
const eventTime = b.event_time || Math.floor(Date.now() / 1000);

// ----- GA4 client_id deterministico desde contacto.id -----
// Formato GA4 esperado: "<random>.<timestamp>" — usamos hash MD5 para que sea estable
const idHash = parseInt(crypto.createHash('md5').update(contactoId).digest('hex').slice(0, 10), 16);
const ga4ClientId = idHash + '.' + eventTime;

// ================================================================
// PAYLOAD META CAPI
// ================================================================
const meta_payload = {
  data: [
    {
      event_name: EVENT_NAME_META,
      event_id: eventId,
      event_time: eventTime,
      event_source_url: sourceUrl,
      action_source: 'website',
      user_data: Object.assign(
        {
          em: email ? [sha256(email)] : [],
          ph: phoneDigits.length > 5 ? [sha256(phoneDigits)] : [],
          fn: firstName ? [sha256(firstName)] : [],
          ln: lastName  ? [sha256(lastName)]  : [],
          external_id: [sha256(contactoId)]
        },
        fbp ? { fbp: fbp } : {},
        fbc ? { fbc: fbc } : {},
        ipAddress ? { client_ip_address: ipAddress } : {},
        userAgent ? { client_user_agent: userAgent } : {}
      ),
      custom_data: {
        currency: EVENT_CURRENCY,
        value: EVENT_VALUE,
        content_name: EVENT_NAME_META,
        content_category: 'Clinica'
      }
    }
  ]
};

// ================================================================
// PAYLOAD GA4 MEASUREMENT PROTOCOL
// ================================================================
const ga4_payload = {
  client_id: ga4ClientId,
  user_id: contactoId,
  timestamp_micros: eventTime * 1000000,
  non_personalized_ads: false,
  events: [
    {
      name: EVENT_NAME_GA4,
      params: Object.assign(
        {
          currency: EVENT_CURRENCY,
          value: EVENT_VALUE,
          engagement_time_msec: 1,
          session_id: eventTime.toString(),
          source: 'clinera',
          medium: 'crm',
          campaign: b.utm_campaign || 'organic'
        },
        fbclid ? { fbclid: fbclid } : {},
        gclid  ? { gclid: gclid }   : {}
      )
    }
  ]
};

// User properties (enriquece reportes GA4)
if (email) {
  ga4_payload.user_properties = {
    email_hash: { value: sha256(email) }
  };
}

return [
  {
    json: {
      event_id: eventId,
      event_name_meta: EVENT_NAME_META,
      event_name_ga4: EVENT_NAME_GA4,
      contacto_id: contactoId,
      meta_payload: meta_payload,
      ga4_payload: ga4_payload
    }
  }
];
